module watchdog_timer (
  input clk,
  input reset,
  input [31:0] timer_duration,
  output reg timer_reset
);

reg [31:0] unused_timer_count;

always @(posedge clk or posedge reset) begin
  if (reset) begin
    unused_timer_count <= 0;
    timer_reset <= 0;
  end else begin
    unused_timer_count <= unused_timer_count + 1;
    if (unused_timer_count >= timer_duration) begin
      unused_timer_count <= 0;
      timer_reset <= 1;
    end else begin
      timer_reset <= 0;
    end
  end
end

endmodule
